// ---- Config ----
const input = $input.first().json;
const CHUNK_SIZE = input.CHUNK_SIZE;
const CHUNK_OVERLAP = input.CHUNK_OVERLAP;

// ---- Input ----
const rawText = input.text;
if (!rawText || typeof rawText !== "string" || !rawText.trim()) {
  return [];
}

// ---- Helpers to classify lines ----
function isHeading(line) {
  const trimmed = line.trim();
  // Markdown-style headings: #, ##, ### etc.
  return /^#{1,6}\s+/.test(trimmed);
}

function isTableLine(line) {
  const trimmed = line.trim();
  if (!trimmed) return false;
  // Simple Markdown table heuristic: line starts with '|' or contains pipes on both sides
  if (trimmed.startsWith("|")) return true;
  return /\|.+\|/.test(trimmed);
}

// ---- Step 1: Group lines into logical blocks (heading, table, text) ----
const lines = rawText.split(/\r?\n/);

const blocks = [];
let currentBlock = { type: null, text: "" };

function pushCurrentBlock() {
  if (currentBlock.type && currentBlock.text.trim().length > 0) {
    blocks.push({
      type: currentBlock.type,
      text: currentBlock.text.trimEnd() + "\n"
    });
  }
  currentBlock = { type: null, text: "" };
}

for (let idx = 0; idx < lines.length; idx++) {
  const line = lines[idx];
  const trimmed = line.trim();

  // Blank line: terminate current block
  if (!trimmed) {
    pushCurrentBlock();
    continue;
  }

  const heading = isHeading(line);
  const table = isTableLine(line);
  const lineType = heading ? "heading" : (table ? "table" : "text");

  if (!currentBlock.type) {
    // Start a new block
    currentBlock.type = lineType;
    currentBlock.text = line + "\n";
  } else {
    // Special case: allow heading + table to be merged into one block
    if (currentBlock.type === "heading" && lineType === "table") {
      currentBlock.type = "heading_table";
      currentBlock.text += line + "\n";
    } else if (lineType === currentBlock.type) {
      // Same type: continue the block (e.g. multi-line table or paragraph)
      currentBlock.text += line + "\n";
    } else {
      // Different type: close current block and start a new one
      pushCurrentBlock();
      currentBlock.type = lineType;
      currentBlock.text = line + "\n";
    }
  }
}
pushCurrentBlock(); // flush last block

// ---- Step 2: Turn blocks into chunks without splitting tables ----
const chunkTexts = [];
let chunkStartIndex = 0;
let currentLen = 0;

// Precompute block lengths for convenience
const blockLengths = blocks.map(b => b.text.length);

for (let i = 0; i < blocks.length; i++) {
  const blockLen = blockLengths[i];

  // If adding this block would exceed CHUNK_SIZE and we already have some content, cut a chunk here
  if (currentLen > 0 && currentLen + blockLen > CHUNK_SIZE) {
    // Build chunk from [chunkStartIndex, i)
    const chunk = blocks
      .slice(chunkStartIndex, i)
      .map(b => b.text)
      .join("\n")
      .trim();

    if (chunk.length > 10) {
      chunkTexts.push(chunk);
    }

    // ---- Overlap: move start index backward to include previous blocks up to CHUNK_OVERLAP chars ----
    let overlapLen = 0;
    let newStart = i - 1;
    while (newStart > chunkStartIndex && overlapLen + blockLengths[newStart] <= CHUNK_OVERLAP) {
      overlapLen += blockLengths[newStart];
      newStart--;
    }

    chunkStartIndex = Math.max(0, newStart);
    // Recompute currentLen from newStart up to (but not including) i
    currentLen = 0;
    for (let j = chunkStartIndex; j < i; j++) {
      currentLen += blockLengths[j];
    }
  }

  // Add current block to the running chunk
  currentLen += blockLen;
}

// Flush the final chunk
if (chunkStartIndex < blocks.length) {
  const finalChunk = blocks
    .slice(chunkStartIndex)
    .map(b => b.text)
    .join("\n")
    .trim();
  if (finalChunk.length > 10) {
    chunkTexts.push(finalChunk);
  }
}

// ---- Step 3: Build embedding requests ----
const requests = chunkTexts.map((chunkText) => ({
  content: {
    parts: [{ text: chunkText }]
  }
}));

// ---- Output ----
return [{ json: { requests } }];
